      1: process.stdout.fd,  // Standard output
      2: process.stderr.fd   // Standard error
    };
    this.fdToStreamMap = {
      [process.stdin.fd]: process.stdin,
      [process.stdout.fd]: process.stdout,
      [process.stderr.fd]: process.stderr
