/* 64-bit integer helper routines (compiler-rt/libgcc replacements),
   implemented using only 32-bit operations so they never recurse. */
typedef unsigned int u32;
typedef int s32;
typedef unsigned long long u64;
typedef long long s64;

u64 __lshrdi3(u64 a, int b){
  b &= 63;
  if(b==0) return a;
  u32 lo=(u32)a, hi=(u32)(a>>32);
  u32 rlo, rhi;
  if(b<32){ rlo=(lo>>b)|(hi<<(32-b)); rhi=hi>>b; }
  else { rlo=hi>>(b-32); rhi=0; }
  return ((u64)rhi<<32)|rlo;
}
u64 __ashldi3(u64 a, int b){
  b &= 63;
  if(b==0) return a;
  u32 lo=(u32)a, hi=(u32)(a>>32);
  u32 rlo, rhi;
  if(b<32){ rhi=(hi<<b)|(lo>>(32-b)); rlo=lo<<b; }
  else { rhi=lo<<(b-32); rlo=0; }
  return ((u64)rhi<<32)|rlo;
}
s64 __ashrdi3(s64 a, int b){
  b &= 63;
  if(b==0) return a;
  u32 lo=(u32)a; s32 hi=(s32)(a>>32);
  u32 rlo; s32 rhi;
  if(b<32){ rlo=((u32)hi<<(32-b))|(lo>>b); rhi=hi>>b; }
  else { rlo=(u32)(hi>>(b-32)); rhi=hi>>31; }
  return ((u64)(u32)rhi<<32)|rlo;
}

u64 __udivmoddi4(u64 n, u64 d, u64 *rem){
  if(d==0){ if(rem)*rem=0; return ~0ULL; }
  if(d>n){ if(rem)*rem=n; return 0; }
  /* fast path: 32-bit / 32-bit */
  if((n>>32)==0 && (d>>32)==0){
    u32 nn=(u32)n, dd=(u32)d;
    if(rem)*rem=nn%dd; return nn/dd;
  }
  u64 q=0, r=0;
  int i;
  for(i=63;i>=0;i--){
    r = (r<<1) | ((n>>i)&1ULL);
    if(r>=d){ r-=d; q |= (1ULL<<i); }
  }
  if(rem)*rem=r;
  return q;
}
u64 __udivdi3(u64 n, u64 d){ return __udivmoddi4(n,d,0); }
u64 __umoddi3(u64 n, u64 d){ u64 r; __udivmoddi4(n,d,&r); return r; }
s64 __divdi3(s64 a, s64 b){
  int neg=0; u64 ua,ub;
  if(a<0){ ua=(u64)(-a); neg^=1; } else ua=(u64)a;
  if(b<0){ ub=(u64)(-b); neg^=1; } else ub=(u64)b;
  u64 q=__udivdi3(ua,ub); return neg?-(s64)q:(s64)q;
}
s64 __moddi3(s64 a, s64 b){
  int neg=(a<0); u64 ua,ub,r;
  if(a<0) ua=(u64)(-a); else ua=(u64)a;
  if(b<0) ub=(u64)(-b); else ub=(u64)b;
  __udivmoddi4(ua,ub,&r); return neg?-(s64)r:(s64)r;
}
u64 __muldi3(u64 a, u64 b){
  u32 al=(u32)a, ah=(u32)(a>>32), bl=(u32)b, bh=(u32)(b>>32);
  u64 ll=(u64)al*bl;
  u64 mid=(u64)al*bh + (u64)ah*bl;
  u64 res=ll + (mid<<32);
  return res;
}
