/* Minimal IEEE-754 soft-float: double add/sub/mul/div, conversions,
   comparisons; single precision via double. Integer-only. */
typedef unsigned int u32;
typedef int s32;
typedef unsigned long long u64;
typedef long long s64;

typedef union { double d; u64 u; } D;
typedef union { float f; u32 u; } F;

#define EXPBITS 0x7FFULL
#define DBIAS 1023

/* unpack: value = (-1)^sign * sig * 2^E ; sig has bit63 set for normals; sig==0 for zero */
typedef struct { int sign; int E; u64 sig; int cls; } dparts; /* cls:0 normal/zero,1 inf,2 nan */

static dparts unpack(u64 bits){
  dparts p;
  p.sign = (int)(bits>>63)&1;
  int e = (int)((bits>>52)&EXPBITS);
  u64 m = bits & 0xFFFFFFFFFFFFFULL;
  if(e==0x7FF){ p.cls = m?2:1; p.sig=m; p.E=0; return p; }
  p.cls = 0;
  if(e==0){
    if(m==0){ p.sig=0; p.E=0; return p; }
    /* subnormal: normalize */
    u64 sig = m; int E = 1-DBIAS-52;
    while(!(sig & 0x10000000000000ULL)){ sig<<=1; E--; }
    /* now bit52 set; shift to bit63 */
    sig<<=11; E-=11;
    p.sig=sig; p.E=E; return p;
  }
  u64 sig = (m | 0x10000000000000ULL) << 11; /* bit63 set */
  p.sig=sig; p.E = e - DBIAS - 52 - 11;
  return p;
}

/* pack from sign, sig(bit63 normalized or 0), E with round-to-nearest-even-ish */
static u64 packd(int sign, u64 sig, int E){
  if(sig==0) return ((u64)sign<<63);
  /* normalize so bit63 set */
  while(!(sig & 0x8000000000000000ULL)){ sig<<=1; E--; }
  /* we need 53-bit significand: value = sig * 2^E ; want (sig>>11) with exponent */
  /* rounding: round bit is bit10, sticky bits below */
  u64 roundbit = sig & 0x400ULL;
  u64 sticky = sig & 0x3FFULL;
  u64 frac53 = sig >> 11;         /* 53 bits, bit52 set */
  int e = E + 11 + 52 + DBIAS;    /* biased exponent */
  /* round half to even */
  if(roundbit && (sticky || (frac53 & 1ULL))){
    frac53++;
    if(frac53 & 0x20000000000000ULL){ /* overflow to bit53 */
      frac53 >>= 1; e++;
    }
  }
  if(e >= 0x7FF){ /* overflow -> inf */
    return ((u64)sign<<63) | (0x7FFULL<<52);
  }
  if(e <= 0){ /* underflow -> flush to zero (subnormals approximated) */
    return ((u64)sign<<63);
  }
  u64 mant = frac53 & 0xFFFFFFFFFFFFFULL;
  return ((u64)sign<<63) | ((u64)e<<52) | mant;
}

static u64 make_inf(int s){ return ((u64)s<<63)|(0x7FFULL<<52); }
static u64 make_nan(void){ return (0x7FFULL<<52)|0x8000000000000ULL; }

static u64 dadd_bits(u64 abits, u64 bbits){
  dparts a=unpack(abits), b=unpack(bbits);
  if(a.cls==2||b.cls==2) return make_nan();
  if(a.cls==1||b.cls==1){
    if(a.cls==1&&b.cls==1){ if(a.sign!=b.sign) return make_nan(); return make_inf(a.sign); }
    return a.cls==1?make_inf(a.sign):make_inf(b.sign);
  }
  if(a.sig==0) return bbits;
  if(b.sig==0) return abits;
  /* align to larger E */
  int Ea=a.E, Eb=b.E; u64 sa=a.sig, sb=b.sig; int E;
  if(Ea>=Eb){
    E=Ea; int d=Ea-Eb; u64 sticky=0;
    if(d>=64){ sticky=sb!=0; sb=0; }
    else if(d>0){ sticky=(sb & ((1ULL<<d)-1))!=0; sb>>=d; }
    if(sticky) sb|=1;
  } else {
    E=Eb; int d=Eb-Ea; u64 sticky=0;
    if(d>=64){ sticky=sa!=0; sa=0; }
    else if(d>0){ sticky=(sa & ((1ULL<<d)-1))!=0; sa>>=d; }
    if(sticky) sa|=1;
  }
  int sign; u64 sig;
  if(a.sign==b.sign){
    sign=a.sign;
    u64 s=sa+sb;
    if(s < sa){ /* carry out of bit63 */
      u64 lost = s & 1; s = (s>>1) | 0x8000000000000000ULL; if(lost) s|=1; E++;
    }
    sig=s;
  } else {
    /* subtract smaller from larger */
    if(sa>=sb){ sign=a.sign; sig=sa-sb; }
    else { sign=b.sign; sig=sb-sa; }
    if(sig==0) return 0; /* +0 */
  }
  return packd(sign, sig, E);
}

double __adddf3(double A, double B){ D a,b,r; a.d=A;b.d=B; r.u=dadd_bits(a.u,b.u); return r.d; }
double __subdf3(double A, double B){ D a,b,r; a.d=A;b.d=B; b.u ^= 0x8000000000000000ULL; r.u=dadd_bits(a.u,b.u); return r.d; }

static u64 dmul_bits(u64 abits, u64 bbits){
  dparts a=unpack(abits), b=unpack(bbits);
  int sign=a.sign^b.sign;
  if(a.cls==2||b.cls==2) return make_nan();
  if(a.cls==1||b.cls==1){
    if((a.cls==1&&b.sig==0&&b.cls==0)||(b.cls==1&&a.sig==0&&a.cls==0)) return make_nan();
    return make_inf(sign);
  }
  if(a.sig==0||b.sig==0) return ((u64)sign<<63);
  /* 64x64 -> high 64 bits of 128-bit product */
  u32 al=(u32)a.sig, ah=(u32)(a.sig>>32), bl=(u32)b.sig, bh=(u32)(b.sig>>32);
  u64 ll=(u64)al*bl;
  u64 lh=(u64)al*bh;
  u64 hl=(u64)ah*bl;
  u64 hh=(u64)ah*bh;
  u64 mid = (ll>>32) + (lh & 0xFFFFFFFFULL) + (hl & 0xFFFFFFFFULL);
  u64 hi  = hh + (lh>>32) + (hl>>32) + (mid>>32);
  u64 lo_low = (ll & 0xFFFFFFFFULL) | ((mid & 0xFFFFFFFFULL)<<32); /* low 64 bits */
